以下程序模拟了一个简单的小球反弹过程，横线处应该填入的是（ ）
```cpp
#include <iostream>
using namespace std;

int main() {
    int height = 10;
    int distance = 0;
    for (int i = 1; i <= 5; i++) { // 模拟5次落地
        ——————————————————————
        height /= 2;
        distance += height;
    }
    cout << distance << endl;
    return 0;
}
```
